<?php
require_once __DIR__.'/helpers.php';require_login();$pageTitle='Donasi Saya';$stmt=db()->prepare('SELECT d.*,c.title campaign_title,c.slug FROM donations d JOIN campaigns c ON c.id=d.campaign_id WHERE d.user_id=? OR d.email=? ORDER BY d.created_at DESC');$stmt->execute([user()['id'],user()['email']]);$donations=$stmt->fetchAll();$verified=array_sum(array_map(fn($d)=>$d['status']==='verified'?(float)$d['amount']:0,$donations));include __DIR__.'/partials/header.php';?>
<section class="page-hero container"><span class="eyebrow">Dashboard donatur</span><h1>Halo, <?=e(user()['name'])?></h1><p>Pantau status dan bukti seluruh donasi Anda.</p></section><section class="container section top-tight"><div class="metric-grid compact-metrics"><div class="metric glass"><span>Total terverifikasi</span><strong><?=money($verified)?></strong></div><div class="metric glass"><span>Jumlah donasi</span><strong><?=count($donations)?></strong></div><div class="metric glass"><span>Menunggu verifikasi</span><strong><?=count(array_filter($donations,fn($d)=>$d['status']==='pending'))?></strong></div></div><div class="glass panel"><div class="section-head"><h2>Riwayat donasi</h2><a class="btn primary small" href="<?=url('campaigns.php')?>">Donasi lagi</a></div><div class="data-table"><table><thead><tr><th>Tanggal</th><th>Kampanye</th><th>Nominal</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($donations as $d):?><tr><td><?=date('d/m/Y',strtotime($d['created_at']))?></td><td><a href="<?=url('campaign.php?slug='.urlencode($d['slug']))?>"><?=e($d['campaign_title'])?></a></td><td><?=money((float)$d['amount'])?></td><td><span class="status <?=e($d['status'])?>"><?=e(ucfirst($d['status']))?></span></td><td><a class="text-link" href="<?=url('receipt.php?code='.urlencode($d['receipt_code']))?>">Bukti</a></td></tr><?php endforeach;?></tbody></table><?php if(!$donations):?><div class="empty-inline">Belum ada donasi.</div><?php endif;?></div></div></section>
<?php include __DIR__.'/partials/footer.php'; ?>
